438	    std::pair<std::vector<torch::Tensor>, std::function<void()>>
439	    all_gather(const std::vector<torch::Tensor>& tensors) {
440	        const int num_tensors = tensors.size();
441	        EP_HOST_ASSERT(num_max_agrs_session_bytes > 0 and num_max_agrs_per_session > 0 and agrs_in_session);
442	        EP_HOST_ASSERT(num_tensors >= 1);
443	
444	        int num_copies = 0;
445	        std::vector<int64_t> offset(num_tensors);
446	        for (int i = 0; i < num_tensors; ++ i) {
447	            const auto& x = tensors[i];
448	            EP_HOST_ASSERT(x.is_contiguous());
449	
450	            const auto x_offset = math::ptr_diff(x.data_ptr(), buffer);
451	            const bool is_inplace = 0 <= x_offset and x_offset < num_max_agrs_session_bytes;
452	            offset[i] = agrs_buffer_offset;
453	            num_copies += nccl_context->num_ranks - is_inplace;
454	            agrs_buffer_offset += math::align<int64_t>(x.nbytes() * nccl_context->num_ranks, 32);
455	            EP_HOST_ASSERT(not is_inplace or x.data_ptr() == math::advance_ptr(buffer, offset[i] + x.nbytes() * nccl_context->rank_idx));
456	        }
457	        EP_HOST_ASSERT(agrs_buffer_offset <= num_max_agrs_session_bytes and
458	                       agrs_buffer_slot_idx < num_max_agrs_per_session and
459	                       "Not enough session buffer size. Did you forget to flush session?");
460	
461	        // Wait compute stream
462	        const auto compute_stream = at::cuda::getCurrentCUDAStream();
463	        stream_wait(comm_stream, compute_stream);
464	
465	        // Send data to all ranks
466	        std::vector<size_t> sizes(num_copies);
467	        std::vector<void*> dst_ptrs(num_copies), src_ptrs(num_copies);
468	        int count = 0;
469	        for (int i = 0; i < nccl_context->num_ranks; ++ i) {
470	            for (int j = 0; j < num_tensors; ++ j) {
471	                const auto& x = tensors[j];
472	                const auto dst_rank_idx = (nccl_context->rank_idx + i) % nccl_context->num_ranks;
473	                void* src_ptr = x.data_ptr();
474	                void* dst_ptr =
475	                    nccl_context->get_sym_ptr(math::advance_ptr(buffer, offset[j] + x.nbytes() * nccl_context->rank_idx), dst_rank_idx);
476	                if (src_ptr != dst_ptr) {
477	                    src_ptrs[count] = src_ptr;
478	                    dst_ptrs[count] = dst_ptr;
479	                    sizes[count] = x.nbytes();
480	                    count += 1;
481	                }
482	            }
483	        }
484	        cudaMemcpyAttributes attrs = {
485	            .srcAccessOrder = cudaMemcpySrcAccessOrderStream,
486	            .flags = cudaMemcpyFlagPreferOverlapWithCompute
487	        };
488	#if defined(CUDART_VERSION) and CUDART_VERSION >= 13000
489	        CUDA_RUNTIME_CHECK(cudaMemcpyBatchAsync(dst_ptrs.data(), src_ptrs.data(), sizes.data(), num_copies, attrs, comm_stream));
490	#else
491	        CUDA_RUNTIME_CHECK(cudaMemcpyBatchAsync(dst_ptrs.data(), src_ptrs.data(), sizes.data(), num_copies, attrs, nullptr, comm_stream));
492	#endif
493	
494	        // Wait for data from other ranks
495	        const int current_session = agrs_session_idx;
496	        const int slot_idx = agrs_buffer_slot_idx;
497	        agrs_buffer_slot_idx += 1;
498	        std::vector<void*> write_ptrs(nccl_context->num_ranks - 1);
499	        std::vector<void*> wait_ptrs(nccl_context->num_ranks - 1);
500	        for (int i = 0; i < nccl_context->num_ranks - 1; ++ i) {
501	            const auto dst_rank_idx = (nccl_context->rank_idx + i + 1) % nccl_context->num_ranks;
502	            write_ptrs[i] = nccl_context->get_sym_ptr(
503	                workspace_layout_wo_expert->get_agrs_recv_signal_ptr(slot_idx, nccl_context->rank_idx), dst_rank_idx);
504	            wait_ptrs[i] = workspace_layout_wo_expert->get_agrs_recv_signal_ptr(slot_idx, dst_rank_idx);
505	        }
506	        cuda_driver::batched_write_and_wait(comm_stream, write_ptrs, wait_ptrs, current_session);
507	
508	        // Build output tensors eagerly
509	        std::vector<torch::Tensor> out(num_tensors);
510	        for (int i = 0; i < num_tensors; ++ i) {
511	            auto shape = tensors[i].sizes().vec();
512	            shape.insert(shape.begin(), nccl_context->num_ranks);
513	            out[i] = torch::from_blob(math::advance_ptr(buffer, offset[i]), shape, tensors[i].options());
514	        }
515	
516	        // Return tensors and a handle to wait for data arrival
517	        const auto event = EventHandle(comm_stream);
518	        auto handle = [=, this]() {
519	            EP_HOST_ASSERT(compute_stream == at::cuda::getCurrentCUDAStream());
520	            EP_HOST_ASSERT(agrs_in_session and current_session == this->agrs_session_idx);
521	            stream_wait(compute_stream, event);
522	        };
523	        return {std::move(out), std::move(handle)};
524	    }
525	
526	    torch::cuda::CUDAStream stream_control_prologue(const std::optional<EventHandle>& previous_event,
527	                                                    const bool& allocate_on_comm_stream,
528	                                                    const bool& async_with_compute_stream) const {
529	        // Allocate all tensors on communication stream if set
530	        // NOTES: do not allocate tensors upfront!
531	        const auto compute_stream = at::cuda::getCurrentCUDAStream();
532	        if (allocate_on_comm_stream)
533	            at::cuda::setCurrentCUDAStream(comm_stream);
534	
535	        // Assertion for safety
536	        // `previous_event` implicitly means the overlapping computation kernels are launched first,
537	        // in order not to use the memory on the compute stream, we must allocate on the communication stream.
538	        // If you launch the communication kernels firstly, then `previous_event` must be unnecessary.
539	        if (previous_event.has_value())
540	            EP_HOST_ASSERT(allocate_on_comm_stream);
541	
542	        // Wait previous tasks to finish
543	        if (previous_event.has_value()) {
544	            stream_wait(comm_stream, previous_event.value());
545	        } else {
546	            stream_wait(comm_stream, compute_stream);
547	        }
548	        return compute_stream;
549	    }
550	
551	    void stream_control_before_epilogue(const std::optional<EventHandle>& previous_event_before_epilogue) const {
552	        if (previous_event_before_epilogue.has_value())
553	            stream_wait(comm_stream, previous_event_before_epilogue.value());
554	    }
555	
556	    std::optional<EventHandle> stream_control_epilogue(const std::vector<std::optional<torch::Tensor>>& tensors,
557	                                                       const at::cuda::CUDAStream& compute_stream,
558	                                                       const bool& allocate_on_comm_stream,
559	                                                       const bool& async_with_compute_stream) const {
560	        // Ensure memory access safety between two streams
561	        std::optional<EventHandle> event;
562	        if (async_with_compute_stream) {
563	            event = EventHandle(comm_stream);
564	
565	            // NOTES: this environment only applies to V2 APIs
566	            if (get_env<int>("EP_AVOID_RECORD_STREAM", 0)) {
567	                event->tensors_to_record = tensors;
568	            } else {
569	                for (auto& t: tensors) if (t.has_value()) {
570	                    t->record_stream(compute_stream);
571	                    t->record_stream(comm_stream);
572	                }
573	            }
574	        } else {
575	            stream_wait(compute_stream, comm_stream);
576	        }
577	
578	        // Switch back compute stream
579	        if (allocate_on_comm_stream)
580	            at::cuda::setCurrentCUDAStream(compute_stream);
581	
582	        // The CUDA event marking the finishing
583	        return event;
584	    }
