940	                EP_HOST_ASSERT(channel_linked_list->is_cuda() and channel_linked_list->is_contiguous());
941	                EP_HOST_ASSERT(channel_linked_list->scalar_type() == torch::kInt);
942	            } else {
943	                channel_linked_list = torch::empty(
