966	                       nccl_context->is_scaleup_nvlink) <= num_buffer_bytes);
967	
968	        // Ready and clean host workspace for this round
969	        const auto host_workspace_layout = layout::WorkspaceLayout(
970	            host_workspace,
971	            nccl_context->num_scaleout_ranks,
972	            nccl_context->num_scaleup_ranks,
973	            num_experts);
974	        std::fill_n(host_workspace_layout.get_scaleup_rank_count_ptr<false>(), nccl_context->num_scaleup_ranks, 0);
975	        std::fill_n(host_workspace_layout.get_scaleup_expert_count_ptr<false>(), num_local_experts, 0);
976	        std::atomic_thread_fence(std::memory_order_seq_cst);
977	
978	        // Do dispatch into the buffers (with SM limitation)
979	        EP_HOST_ASSERT(num_sms <= jit::device_runtime->get_num_sms());
980	        launch_dispatch(x.data_ptr(), sf_ptr,
981	                        topk_idx.data_ptr<topk_idx_t>(), topk_weights_ptr,
