990	                        hidden, x.element_size(),
991	                        num_sf_packs, sf_token_stride, sf_hidden_stride,
992	                        num_experts, num_topk, expert_alignment,
993	                        nccl_context->dev_comm, nccl_context->window,
994	                        buffer,
995	                        workspace, mapped_host_workspace,
996	                        nccl_context->scaleout_rank_idx, nccl_context->scaleup_rank_idx,
997	                        nccl_context->num_scaleout_ranks, nccl_context->num_scaleup_ranks,
998	                        nccl_context->is_scaleup_nvlink,
999	                        num_sms, num_channels_per_sm,
1000	                        num_smem_bytes,
1001	                        num_qps, num_gpu_timeout_cycles,
1002	                        cached_mode, do_cpu_sync,
1003	                        comm_stream);
