1070	            num_expanded_tokens = math::align(num_expanded_tokens, expert_alignment);
1071	        }
1072	
1073	        // Allocate received tensors
1074	        // `recv_src_metadata` includes source token indices and buffer slot indices
1075	        const auto num_allocated_tokens = do_expand ? num_expanded_tokens : num_recv_tokens;
1076	        auto recv_x = torch::empty({num_allocated_tokens, hidden}, x.options());
1077	        auto recv_sf = std::optional<torch::Tensor>();
1078	        auto recv_topk_idx = std::optional<torch::Tensor>();
1079	        auto recv_topk_weights = std::optional<torch::Tensor>();
1080	        auto recv_src_metadata = cached_mode ?
