1101	        }
1102	        if (not do_expand) {
1103	            recv_topk_idx = torch::empty({num_allocated_tokens, num_topk}, topk_idx.options());
1104	            recv_topk_idx_ptr = recv_topk_idx->data_ptr<topk_idx_t>();
1105	        }
1106	        if (topk_weights.has_value()) {
1107	            recv_topk_weights = do_expand ?
1108	                torch::empty({num_allocated_tokens}, topk_weights->options()) :
1109	                torch::empty({num_allocated_tokens, num_topk}, topk_weights->options());
1110	            recv_topk_weights_ptr = recv_topk_weights->data_ptr<float>();
1111	        }
1112	
1113	        // Process prefix sum, in expanding mode, it is also atomic counters
1114	        if (not cached_mode) {
1115	            if (do_expand) {
