1154	             psum_num_recv_tokens_per_scaleup_rank,
1155	             psum_num_recv_tokens_per_expert,
1156	             num_unaligned_recv_tokens_per_expert,
1157	             recv_src_metadata,
1158	             dst_buffer_slot_idx,
1159	             token_metadata_at_forward,
1160	             channel_linked_list},
1161	            compute_stream,
1162	            allocate_on_comm_stream, async_with_compute_stream);
