1179	    std::tuple<torch::Tensor, std::optional<torch::Tensor>, std::optional<EventHandle>>
1180	    combine(const torch::Tensor& x,
1181	            const std::optional<torch::Tensor>& topk_weights,
1182	            const std::optional<torch::Tensor>& bias_0,
1183	            const std::optional<torch::Tensor>& bias_1,
1184	            const torch::Tensor& src_metadata,
1185	            const torch::Tensor& combined_topk_idx,
1186	            const torch::Tensor& psum_num_recv_tokens_per_scaleup_rank,
1187	            const std::optional<torch::Tensor>& token_metadata_at_forward,
1188	            const std::optional<torch::Tensor>& channel_linked_list,
1189	            const int& num_experts,
1190	            const int& num_max_tokens_per_rank,
1191	            const int& num_sms, const int& num_qps,
1192	            const std::optional<EventHandle>& previous_event,
1193	            const std::optional<EventHandle>& previous_event_before_epilogue,
1194	            const bool& async_with_compute_stream,
1195	            const bool& allocate_on_comm_stream,
1196	            const bool& use_expanded_layout) const {
1197	        // Check SM count
1198	        EP_HOST_ASSERT(num_sms > 0);
1199	
1200	        // Check data
1201	        const auto [num_tokens, hidden] = get_shape<2>(x);
1202	        EP_HOST_ASSERT(x.is_cuda() and x.is_contiguous());
1203	        EP_HOST_ASSERT(x.scalar_type() == torch::kBFloat16);
1204	        EP_HOST_ASSERT((x.size(1) * x.element_size()) % sizeof(int4) == 0);
1205	
1206	        // Check tensors at dispatch
1207	        const auto [num_combined_tokens, num_topk] = get_shape<2>(combined_topk_idx);
1208	        const auto [num_scaleup_ranks] = get_shape<1>(psum_num_recv_tokens_per_scaleup_rank);
1209	        EP_HOST_ASSERT(combined_topk_idx.is_cuda() and combined_topk_idx.is_contiguous());
1210	        EP_HOST_ASSERT(combined_topk_idx.scalar_type() == c10::CppTypeToScalarType<topk_idx_t>::value);
1211	        EP_HOST_ASSERT(num_scaleup_ranks == nccl_context->num_scaleup_ranks);
1212	        EP_HOST_ASSERT(psum_num_recv_tokens_per_scaleup_rank.is_cuda() and psum_num_recv_tokens_per_scaleup_rank.is_contiguous());
1213	        EP_HOST_ASSERT(psum_num_recv_tokens_per_scaleup_rank.scalar_type() == torch::kInt);
1214	        EP_HOST_ASSERT(num_combined_tokens <= num_max_tokens_per_rank);
1215	
1216	        // Check metadata
1217	        // For reduction mode, `num_tokens_` means the number of unexpanded tokens
1218	        const auto [num_reduced_tokens, num_topk_p2] = get_shape<2>(src_metadata);
1219	        EP_HOST_ASSERT(num_reduced_tokens == (use_expanded_layout ? num_reduced_tokens : num_tokens));
1220	        EP_HOST_ASSERT(num_topk_p2 == num_topk + 2);
1221	        EP_HOST_ASSERT(src_metadata.is_cuda() and src_metadata.is_contiguous());
1222	        EP_HOST_ASSERT(src_metadata.scalar_type() == torch::kInt);
1223	
1224	        // Check optional tensors
1225	        if (topk_weights.has_value()) {
1226	            if (use_expanded_layout) {
1227	                const auto [num_tokens__] = get_shape<1>(topk_weights.value());
1228	                EP_HOST_ASSERT(num_tokens == num_tokens__);
1229	            } else {
1230	                const auto [num_tokens__, num_topk__] = get_shape<2>(topk_weights.value());
1231	                EP_HOST_ASSERT(num_tokens == num_tokens__ and num_topk == num_topk__);
1232	            }
1233	            EP_HOST_ASSERT(topk_weights->is_cuda() and topk_weights->is_contiguous());
1234	            EP_HOST_ASSERT(topk_weights->scalar_type() == torch::kFloat);
1235	        }
1236	
1237	        const auto bias_opts = std::vector({bias_0, bias_1});
1238	        void* bias_ptrs[2] = {nullptr, nullptr};
1239	        for (int i = 0; i < 2; ++ i) {
1240	            if (bias_opts[i].has_value()) {
1241	                auto bias = bias_opts[i].value();
1242	                EP_HOST_ASSERT(bias.dim() == 2 and bias.is_contiguous());
1243	                EP_HOST_ASSERT(bias.scalar_type() == x.scalar_type());
1244	                EP_HOST_ASSERT(bias.size(0) == num_combined_tokens and bias.size(1) == hidden);
1245	                bias_ptrs[i] = bias.data_ptr();
1246	            }
1247	        }
1248	
1249	        // Stream control
1250	        // All new tensor allocations should happen after this
1251	        const auto compute_stream = stream_control_prologue(previous_event, allocate_on_comm_stream, async_with_compute_stream);
1252	
1253	        // Check buffer size
1254	        EP_HOST_ASSERT(get_combine_buffer_size(num_max_tokens_per_rank, hidden, num_topk,
1255	                                               nccl_context->num_scaleout_ranks, nccl_context->num_scaleup_ranks,
1256	                                               nccl_context->is_scaleup_nvlink, allow_multiple_reduction) <= num_buffer_bytes);
1257	
1258	        // Optional configs and metadata for hybrid combine
1259	        int num_channels = 1;
1260	        int* token_metadata_at_forward_ptr = nullptr;
1261	        int* channel_linked_list_ptr = nullptr;
1262	        if (nccl_context->num_scaleout_ranks > 1) {
1263	            // The token metadata during forward
1264	            const auto [num_channels_, d1, d2] = get_shape<3>(token_metadata_at_forward.value());
1265	            const auto num_max_tokens_per_channel = math::ceil_div(num_max_tokens_per_rank, num_channels_);
1266	            num_channels = num_channels_;
1267	            token_metadata_at_forward_ptr = token_metadata_at_forward->data_ptr<int>();
1268	            EP_HOST_ASSERT(d1 == nccl_context->num_scaleout_ranks * num_max_tokens_per_channel + 1);
1269	            EP_HOST_ASSERT(d2 == 2 + num_topk * 2);
1270	            EP_HOST_ASSERT(token_metadata_at_forward->is_cuda() and token_metadata_at_forward->is_contiguous());
1271	            EP_HOST_ASSERT(token_metadata_at_forward->scalar_type() == torch::kInt);
1272	
1273	            // Per-scaleup-peer-per-channel linked list
1274	            const auto [num_channels__, d1_, d2_] = get_shape<3>(channel_linked_list.value());
1275	            channel_linked_list_ptr = channel_linked_list->data_ptr<int>();
1276	            EP_HOST_ASSERT(num_channels == num_channels__);
1277	            EP_HOST_ASSERT(d1_ == nccl_context->num_scaleout_ranks * num_max_tokens_per_channel + 1);
1278	            EP_HOST_ASSERT(d2_ == nccl_context->num_scaleup_ranks);
1279	            EP_HOST_ASSERT(channel_linked_list->is_cuda() and channel_linked_list->is_contiguous());
1280	            EP_HOST_ASSERT(channel_linked_list->scalar_type() == torch::kInt);
1281	        }
1282	
1283	        // Push data into remote buffers
1284	        // NOTES: we don't use `num_hidden_bytes` due to enable later quantization possibility
1285	        const auto reduce_buffer = launch_combine(
1286	            x.data_ptr(),
1287	            topk_weights.has_value() ? topk_weights->data_ptr() : nullptr,
1288	            src_metadata.data_ptr<int>(),
1289	            psum_num_recv_tokens_per_scaleup_rank.data_ptr<int>(),
1290	            token_metadata_at_forward_ptr,
1291	            channel_linked_list_ptr,
1292	            nccl_context->dev_comm, nccl_context->window,
1293	            buffer, workspace,
1294	            num_reduced_tokens, num_max_tokens_per_rank,
1295	            hidden, num_experts, num_topk,
1296	            num_qps, num_gpu_timeout_cycles,
1297	            nccl_context->num_scaleout_ranks, nccl_context->num_scaleup_ranks,
1298	            nccl_context->scaleout_rank_idx, nccl_context->scaleup_rank_idx,
1299	            nccl_context->is_scaleup_nvlink,
1300	            num_sms, jit::device_runtime->get_num_smem_bytes(),
1301	            num_channels,
1302	            use_expanded_layout, allow_multiple_reduction,
1303	            comm_stream);
1304	
1305	        // Allocate output tensors
1306	        auto combined_x = torch::empty({num_combined_tokens, hidden}, x.options());
1307	        auto combined_topk_weights = std::optional<torch::Tensor>();
1308	        float* combined_topk_weights_ptr = nullptr;
1309	        if (topk_weights.has_value()) {
1310	            combined_topk_weights = torch::empty({num_combined_tokens, num_topk}, topk_weights->options());
1311	            combined_topk_weights_ptr = combined_topk_weights->data_ptr<float>();
1312	        }
1313	
1314	        // Combine pushed data
1315	        stream_control_before_epilogue(previous_event_before_epilogue);
1316	        launch_combine_reduce_epilogue(combined_x.data_ptr(),
1317	                                       combined_topk_weights_ptr,
1318	                                       combined_topk_idx.data_ptr<topk_idx_t>(),
1319	                                       num_combined_tokens, num_max_tokens_per_rank,
1320	                                       hidden,
1321	                                       num_experts, num_topk,
1322	                                       reduce_buffer,
1323	                                       bias_ptrs[0], bias_ptrs[1],
1324	                                       nccl_context->num_scaleout_ranks, nccl_context->num_scaleup_ranks,
1325	                                       nccl_context->scaleout_rank_idx, nccl_context->scaleup_rank_idx,
1326	                                       jit::device_runtime->get_num_sms(),
1327	                                       jit::device_runtime->get_num_smem_bytes(),
1328	                                       use_expanded_layout, allow_multiple_reduction,
1329	                                       comm_stream);
1330	
1331	        // Stream control
1332	        const auto event = stream_control_epilogue(
1333	            {x, topk_weights, bias_0, bias_1,
1334	             src_metadata,
1335	             combined_topk_idx,
1336	             combined_x, combined_topk_weights,
1337	             psum_num_recv_tokens_per_scaleup_rank,
1338	             token_metadata_at_forward,
1339	             channel_linked_list},
1340	            compute_stream,
1341	            allocate_on_comm_stream, async_with_compute_stream);
1342	        return {combined_x, combined_topk_weights, event};
1343	    }
1344	};
