20	namespace deep_ep::jit {
21	
22	class Compiler {
23	public:
24	    static std::filesystem::path library_root_path;
25	    static std::filesystem::path library_include_path;
26	    static std::filesystem::path cuda_home;
27	    static std::filesystem::path nccl_root;
28	    static std::filesystem::path cuobjdump_path;
29	
30	    static void prepare_init(const std::string& library_root_path,
31	                             const std::string& cuda_home_path_by_python,
32	                             const std::string& nccl_root_path_by_python) {
33	        // NOTES: if you are adding some third-party includes for kernels, please add its hash value
34	        Compiler::library_root_path = library_root_path;
35	        Compiler::library_include_path = Compiler::library_root_path / "include";
36	        Compiler::cuda_home = cuda_home_path_by_python;
37	        Compiler::nccl_root = nccl_root_path_by_python;
38	        Compiler::cuobjdump_path = Compiler::cuda_home / "bin" / "cuobjdump";
39	    }
40	
41	    std::string signature, flags;
42	    std::filesystem::path cache_dir_path;
43	
44	    Compiler() {
45	        EP_HOST_ASSERT(not library_root_path.empty());
46	        EP_HOST_ASSERT(not library_include_path.empty());
47	        EP_HOST_ASSERT(not cuda_home.empty());
48	        EP_HOST_ASSERT(not nccl_root.empty());
49	        EP_HOST_ASSERT(not cuobjdump_path.empty());
50	
51	        // Cache settings
52	        cache_dir_path = std::filesystem::path(get_env<std::string>("HOME")) / ".deep_ep";
53	        if (const auto env_cache_dir_path = get_env<std::string>("EP_JIT_CACHE_DIR"); not env_cache_dir_path.empty())
54	            cache_dir_path = env_cache_dir_path;
55	
56	        // The compiler flags applied to all derived compilers
57	        signature = "unknown-compiler";
58	        flags = fmt::format("-std=c++{} --diag-suppress=39,161,174,177,186,940,3012 "
59	                            "--ptxas-options=--register-usage-level=10",
60	                            get_env<int>("EP_JIT_CPP_STANDARD", 20));
61	        if (get_env("EP_JIT_DEBUG", 0) or get_env("EP_JIT_PTXAS_VERBOSE", 0))
62	            flags += " --ptxas-options=--verbose";
63	        if (get_env("EP_JIT_DEBUG", 0) or get_env("EP_JIT_WITH_LINEINFO", 0))
64	            flags += " -Xcompiler -rdynamic -lineinfo";
65	        if (get_env("EP_GIN_GDAKI_DEBUG", 0))
66	            flags += " -DNCCL_DEVICE_GIN_GDAKI_ENABLE_DEBUG=1";
67	        flags += fmt::format(" -I {}/include", nccl_root.c_str());
68	
69	        // Some special flags for EP
70	        // TODO: make it more general, e.g. `EP_JIT_EXTRA_FLAGS`
71	        if (int num_topk_idx_bits = get_env("EP_NUM_TOPK_IDX_BITS", 0); num_topk_idx_bits != 0)
72	            flags += fmt::format(" -DEP_NUM_TOPK_IDX_BITS={}", num_topk_idx_bits);
73	    }
74	
75	    virtual ~Compiler() = default;
76	
77	    std::filesystem::path make_tmp_dir() const {
78	        return make_dirs(cache_dir_path / "tmp");
79	    }
80	
81	    static void fsync_path(const std::filesystem::path& path) {
82	        const auto fd = ::open(path.c_str(), O_RDONLY);
83	        if (fd >= 0) {
84	            ::fsync(fd);
85	            ::close(fd);
86	        }
87	    }
88	
89	    // Recursively fsync a directory: files and subdirectories first (bottom-up), then the directory itself
90	    // NOTES: ensures data and directory entries are visible on other nodes in distributed filesystems
91	    static void fsync_dir(const std::filesystem::path& dir_path) { // NOLINT(*-no-recursion)
92	        for (const auto& entry: std::filesystem::directory_iterator(dir_path)) {
93	            if (entry.is_directory())
94	                fsync_dir(entry.path());
95	            else if (entry.is_regular_file())
96	                fsync_path(entry.path());
97	        }
98	        fsync_path(dir_path);
99	    }
100	
101	    static void put(const std::filesystem::path& path, const std::string& data) {
102	        std::ofstream out(path, std::ios::binary);
103	        EP_HOST_ASSERT(out.write(data.data(), data.size()));
104	        out.close();
105	
106	        // NOTES: fsync to ensure the data is visible to other processes (e.g., NVCC)
107	        // on distributed filesystems, where `close()` alone does not guarantee persistence
108	        fsync_path(path);
109	    }
110	
111	    std::shared_ptr<KernelRuntime> build(const std::string& name, const std::string& code) const {
112	        const auto kernel_signature = fmt::format("{}$${}$${}$${}", name, signature, flags, code);
113	        const auto dir_path = cache_dir_path / "cache" / fmt::format("kernel.{}.{}", name, get_hex_digest(kernel_signature));
114	
115	        // Hit the runtime cache
116	        if (const auto runtime = kernel_runtime_cache->get(dir_path); runtime != nullptr)
117	            return runtime;
118	
119	        // Compile into a temporary directory, then atomically rename the whole directory
120	        // NOTES: renaming a directory is atomic on both local and distributed filesystems,
121	        // avoiding the stale inode issue that occurs when renaming individual files
122	        const auto tmp_dir_path = make_tmp_dir() / get_uuid();
123	        make_dirs(tmp_dir_path);
124	
125	        // Compile into the temporary directory
126	        const auto tmp_cubin_path = tmp_dir_path / "kernel.cubin";
127	        if (get_env<int>("EP_JIT_DUMP_ASM") or get_env<int>("EP_JIT_DUMP_PTX")) {
128	            const auto tmp_ptx_path = tmp_dir_path / "kernel.ptx";
129	            compile(code, tmp_dir_path, tmp_cubin_path, tmp_ptx_path);
130	        } else {
131	            compile(code, tmp_dir_path, tmp_cubin_path);
132	        }
133	
134	        // Disassemble if needed
135	        if (get_env<int>("EP_JIT_DUMP_ASM") or get_env<int>("EP_JIT_DUMP_SASS")) {
136	            const auto tmp_sass_path = tmp_dir_path / "kernel.sass";
137	            disassemble(tmp_cubin_path, tmp_sass_path);
138	        }
139	
140	        // Fsync before rename to ensure visibility on distributed filesystems
141	        fsync_dir(tmp_dir_path);
142	
143	        // Atomically rename the temporary directory to the final cache path
144	        // NOTES: if another rank already created dir_path, rename will fail — that's fine
145	        make_dirs(dir_path.parent_path());
146	        std::error_code error_code;
147	        std::filesystem::rename(tmp_dir_path, dir_path, error_code);
148	        if (error_code) {
149	            // Another rank beat us, then clean up our dir and use the existing one
150	            // NOTES: avoid `std::filesystem::remove_all` here — it can segfault on
151	            // distributed filesystems, when concurrent processes operate
152	            // on the same parent directory, causing stale directory entries
153	            safe_remove_all(tmp_dir_path);
154	        }
155	
156	        // Put into the runtime cache
157	        const auto runtime = kernel_runtime_cache->get(dir_path);
158	        EP_HOST_ASSERT(runtime != nullptr);
159	        return runtime;
160	    }
161	
162	    static void disassemble(const std::filesystem::path &cubin_path, const std::filesystem::path &sass_path) {
163	        // Disassemble the CUBIN file to SASS
164	        const auto command = fmt::format("{} --dump-sass {} > {}", cuobjdump_path.c_str(), cubin_path.c_str(), sass_path.c_str());
165	        if (get_env("EP_JIT_DEBUG", 0) or get_env("EP_JIT_PRINT_COMPILER_COMMAND", 0))
166	            printf("Running cuobjdump command: %s\n", command.c_str());
167	        const auto [return_code, output] = call_external_command(command);
168	        if (return_code != 0) {
169	            printf("cuobjdump failed: %s\n", output.c_str());
170	            EP_HOST_ASSERT(false and "cuobjdump failed");
171	        }
172	    }
173	
174	    virtual void compile(const std::string &code, const std::filesystem::path& dir_path, const std::filesystem::path &cubin_path, const std::optional<std::filesystem::path> &ptx_path = std::nullopt) const = 0;
175	};
176	
177	EP_DECLARE_STATIC_VAR_IN_CLASS(Compiler, library_root_path);
178	EP_DECLARE_STATIC_VAR_IN_CLASS(Compiler, library_include_path);
179	EP_DECLARE_STATIC_VAR_IN_CLASS(Compiler, cuda_home);
180	EP_DECLARE_STATIC_VAR_IN_CLASS(Compiler, nccl_root);
181	EP_DECLARE_STATIC_VAR_IN_CLASS(Compiler, cuobjdump_path);
182	
183	class NVCCCompiler final: public Compiler {
184	    std::filesystem::path nvcc_path;
185	
186	    std::pair<int, int> get_nvcc_version() const {
187	        EP_HOST_ASSERT(std::filesystem::exists(nvcc_path));
188	
189	        // Call the version command
190	        const auto command = std::string(nvcc_path) + " --version";
191	        const auto [return_code, output] = call_external_command(command);
192	        EP_HOST_ASSERT(return_code == 0);
193	
194	        // The version should be at least 12.3
195	        int major, minor;
196	        std::smatch match;
197	        EP_HOST_ASSERT(std::regex_search(output, match, std::regex(R"(release (\d+\.\d+))")));
198	        std::sscanf(match[1].str().c_str(), "%d.%d", &major, &minor);
199	        EP_HOST_ASSERT((major > 12 or (major == 12 and minor >= 3)) and "NVCC version should be >= 12.3");
200	        return {major, minor};
201	    }
202	
203	public:
204	    NVCCCompiler() {
205	        // Override the compiler signature
206	        nvcc_path = cuda_home / "bin" / "nvcc";
207	        cuobjdump_path = cuda_home / "bin" / "cuobjdump";
208	        if (const auto env_nvcc_path = get_env<std::string>("EP_JIT_NVCC_COMPILER"); not env_nvcc_path.empty())
209	            nvcc_path = env_nvcc_path;
210	        const auto [nvcc_major, nvcc_minor] = get_nvcc_version();
211	        signature = fmt::format("NVCC{}.{}", nvcc_major, nvcc_minor);
212	
213	        // The override the compiler flags
214	        // Only NVCC >= 12.9 supports arch-specific family suffix
215	        const auto arch = device_runtime->get_arch(false, nvcc_major > 12 or nvcc_minor >= 9);
216	        flags = fmt::format("{} -I{} --gpu-architecture=sm_{} "
217	                            "--compiler-options=-fPIC,-O3,-fconcepts,-Wno-deprecated-declarations,-Wno-abi "
218	                            "-O3 --expt-relaxed-constexpr --expt-extended-lambda",
219	                            flags, library_include_path.c_str(), arch);
220	    }
221	
222	    void compile(const std::string &code, const std::filesystem::path& dir_path,
223	                 const std::filesystem::path &cubin_path,
224	                 const std::optional<std::filesystem::path> &ptx_path) const override {
225	        // Write the code into the cache directory
226	        const auto code_path = dir_path / "kernel.cu";
227	        put(code_path, code);
228	
229	        // Compile to CUBIN
230	        // Avoid cwd files shadowing C++ standard library headers
231	        const auto compile_dir = make_tmp_dir();
232	        const auto command = fmt::format("cd {} && {} {} -cubin -o {} {}",
233	            compile_dir.c_str(), nvcc_path.c_str(), code_path.c_str(), cubin_path.c_str(), flags);
234	        if (get_env("EP_JIT_DEBUG", 0) or get_env("EP_JIT_PRINT_COMPILER_COMMAND", 0))
235	            printf("Running NVCC command: %s\n", command.c_str());
236	        const auto [return_code, output] = call_external_command(command);
237	        if (return_code != 0) {
238	            printf("NVCC compilation failed: %s\n", output.c_str());
239	            EP_HOST_ASSERT(false and "NVCC compilation failed");
240	        }
241	
242	        // Compile to PTX if needed
243	        if (ptx_path.has_value()) {
244	            const auto ptx_command = fmt::format("cd {} && {} {} -ptx -o {} {}",
245	                compile_dir.c_str(), nvcc_path.c_str(), code_path.c_str(), ptx_path->c_str(), flags);
246	            if (get_env("EP_JIT_DEBUG", 0) or get_env("EP_JIT_PRINT_COMPILER_COMMAND", 0))
247	                printf("Running NVCC PTX command: %s\n", ptx_command.c_str());
248	            const auto [ptx_return_code, ptx_output] = call_external_command(ptx_command);
249	            if (ptx_return_code != 0) {
250	                printf("NVCC PTX compilation failed: %s\n", ptx_output.c_str());
251	                EP_HOST_ASSERT(false and "NVCC PTX compilation failed");
252	            }
253	        }
254	
255	        // Check local memory usage
256	        if (get_env("EP_JIT_PTXAS_CHECK", 0))
257	            EP_HOST_ASSERT(not std::regex_search(output, std::regex(R"(Local memory used)")));
258	
259	        // Print PTXAS log
260	        if (get_env("EP_JIT_DEBUG", 0) or get_env("EP_JIT_PTXAS_VERBOSE", 0))
261	            printf("%s", output.c_str());
262	    }
263	};
264	
265	static auto compiler = LazyInit<Compiler>([]() -> std::shared_ptr<Compiler> {
266	    return std::make_shared<NVCCCompiler>();
267	});
268	
269	} // namespace deep_ep::jit
