13	
14	class DispatchRuntime final : public jit::LaunchRuntime<DispatchRuntime> {
15	public:
16	    struct Args {
17	        // Templated arguments
18	        bool is_scaleup_nvlink;
19	        bool do_cpu_sync;
20	        bool reuse_slot_indices;
21	        int num_notify_warps;
22	        int num_dispatch_warps; // For hybrid dispatch
23	        int num_scaleout_warps, num_forward_warps; // For direct dispatch
24	        int num_scaleout_ranks, num_scaleup_ranks;
25	        int num_hidden_bytes, num_sf_packs;
26	        int num_max_tokens_per_rank;
27	        int num_experts, num_topk, expert_alignment;
28	        int num_qps;
29	        int64_t num_timeout_cycles;
30	
31	        // Parameters
32	        void* x; sf_pack_t* sf; topk_idx_t* topk_idx; float* topk_weights;
33	        topk_idx_t* copied_topk_idx;
34	        int* cumulative_local_expert_recv_stats;
35	        int* psum_num_recv_tokens_per_scaleup_rank;
36	        int* psum_num_recv_tokens_per_expert;
37	        int* num_unaligned_recv_tokens_per_expert;
38	        int* dst_buffer_slot_idx;
39	        int* token_metadata_at_forward;
40	        int num_tokens;
41	        int sf_token_stride, sf_hidden_stride;
42	        ncclDevComm_t nccl_dev_comm;
43	        ncclWindow_t nccl_window;
44	        void* buffer;
45	        void* workspace; void* mapped_host_workspace;
46	        int scaleout_rank_idx, scaleup_rank_idx;
47	
48	        jit::LaunchArgs launch_args;
49	    };
50	
51	    static std::string generate_impl(const Args& args) {
52	        std::string header_name, func_name;
53	        if (args.num_scaleout_ranks == 1) {
54	            header_name = "dispatch";
55	            func_name = fmt::format("dispatch_impl<{}, {}, {}, {}, {}, {}, {}, {}, {}, {}, {}, {}, {}, {}, {}>",
56	                args.is_scaleup_nvlink,
57	                args.do_cpu_sync,
58	                args.reuse_slot_indices,
59	                args.launch_args.grid_dim.first,
60	                args.num_notify_warps, args.num_dispatch_warps,
61	                args.num_scaleup_ranks,
62	                args.num_hidden_bytes, args.num_sf_packs,
63	                args.num_max_tokens_per_rank,
64	                args.num_experts, args.num_topk, args.expert_alignment,
65	                args.num_qps, args.num_timeout_cycles);
66	        } else {
67	            header_name = "hybrid_dispatch";
68	            func_name = fmt::format("hybrid_dispatch_impl<{}, {}, {}, {}, {}, {}, {}, {}, {}, {}, {}, {}, {}, {}, {}, {}>",
69	                args.do_cpu_sync,
70	                args.reuse_slot_indices,
71	                args.launch_args.grid_dim.first,
72	                args.num_notify_warps, args.num_scaleout_warps, args.num_forward_warps,
73	                args.num_scaleout_ranks, args.num_scaleup_ranks,
74	                args.num_hidden_bytes, args.num_sf_packs,
75	                args.num_max_tokens_per_rank,
76	                args.num_experts, args.num_topk, args.expert_alignment,
77	                args.num_qps, args.num_timeout_cycles);
78	        }
79	
80	        return fmt::format(R"(
81	#include <deep_ep/impls/{}.cuh>
82	
83	using namespace deep_ep::elastic;
84	
85	static void __instantiate_kernel() {{
86	    auto ptr = reinterpret_cast<void*>(&{});
87	}}
88	)", header_name, func_name);
89	    }
90	
91	    static void launch_impl(const jit::KernelHandle& kernel, const jit::LaunchConfigHandle& config, Args args) {
92	        if (args.num_scaleout_ranks == 1) {
93	            EP_CUDA_UNIFIED_CHECK(jit::launch_kernel(
94	                kernel, config,
95	                args.x, args.sf, args.topk_idx, args.topk_weights,
96	                args.copied_topk_idx,
97	                args.cumulative_local_expert_recv_stats,
98	                args.psum_num_recv_tokens_per_scaleup_rank,
99	                args.psum_num_recv_tokens_per_expert,
100	                args.num_unaligned_recv_tokens_per_expert,
101	                args.dst_buffer_slot_idx,
102	                args.num_tokens,
103	                args.sf_token_stride, args.sf_hidden_stride,
104	                args.nccl_dev_comm, args.nccl_window,
105	                args.buffer,
106	                args.workspace, args.mapped_host_workspace,
107	                args.scaleup_rank_idx));
108	        } else {
109	            EP_CUDA_UNIFIED_CHECK(jit::launch_kernel(
110	                kernel, config,
111	                args.x, args.sf, args.topk_idx, args.topk_weights,
112	                args.copied_topk_idx,
113	                args.cumulative_local_expert_recv_stats,
114	                args.psum_num_recv_tokens_per_scaleup_rank,
115	                args.psum_num_recv_tokens_per_expert,
116	                args.num_unaligned_recv_tokens_per_expert,
117	                args.dst_buffer_slot_idx,
118	                args.token_metadata_at_forward,
119	                args.num_tokens,
120	                args.sf_token_stride, args.sf_hidden_stride,
121	                args.nccl_dev_comm, args.nccl_window,
122	                args.buffer,
123	                args.workspace, args.mapped_host_workspace,
124	                args.scaleout_rank_idx, args.scaleup_rank_idx
125	            ));
126	        }
127	    }
128	};
129	
130	constexpr int kNumNotifyWarps = 4;
131	
132	static int get_num_notify_smem_bytes(const int& num_ranks, const int& num_experts) {
133	    return math::align(num_ranks + num_experts, kNumNotifyWarps * 32) * sizeof(int);
134	}
135	
136	static layout::TokenLayout get_dispatch_token_layout(
137	    const int& hidden, const int& elem_size, const int& num_sf_packs, const int& num_topk) {
138	    return layout::TokenLayout(hidden * elem_size, num_sf_packs * sizeof(sf_pack_t), num_topk, true);
139	}
140	
141	static void launch_dispatch(void* x, void* sf,
142	                            topk_idx_t* topk_idx, float* topk_weights,
143	                            topk_idx_t* copied_topk_idx,
144	                            int* cumulative_local_expert_recv_stats,
145	                            int* psum_num_recv_tokens_per_scaleup_rank,
146	                            int* psum_num_recv_tokens_per_expert,
147	                            int* num_unaligned_recv_tokens_per_expert,
148	                            int* dst_buffer_slot_idx,
149	                            int* token_metadata_at_forward,
150	                            const int& num_tokens, const int& num_max_tokens_per_rank,
151	                            const int& hidden, const int& elem_size,
152	                            const int& num_sf_packs, const int& sf_token_stride, const int& sf_hidden_stride,
153	                            const int& num_experts, const int& num_topk, const int& expert_alignment,
154	                            const ncclDevComm_t& nccl_dev_comm, const ncclWindow_t& nccl_window,
155	                            void* buffer,
156	                            void* workspace, void* mapped_host_workspace,
157	                            const int& scaleout_rank_idx, const int& scaleup_rank_idx,
158	                            const int& num_scaleout_ranks, const int& num_scaleup_ranks,
159	                            const bool& is_scaleup_nvlink,
160	                            const int& num_sms, const int& num_channels_per_sm,
161	                            const int& num_smem_bytes,
162	                            const int& num_qps, const int64_t& num_timeout_cycles,
163	                            const bool& cached_mode,
164	                            const bool& do_cpu_sync,
165	                            const at::cuda::CUDAStream& stream) {
166	    // Cached mode does not support expert token counting
167	    if (cached_mode)
168	        EP_HOST_ASSERT(cumulative_local_expert_recv_stats == nullptr);
169	
170	    // Utils
171	    const auto num_ranks = num_scaleout_ranks * num_scaleup_ranks;
172	
173	    // Notify warps
174	    // TODO: why don't we use 4 notify warps?
175	    const int num_notify_warps = cached_mode ? 0 : kNumNotifyWarps;
176	    const bool reuse_slot_indices = cached_mode;
177	    const int num_notify_smem_bytes = cached_mode ? 0 : get_num_notify_smem_bytes(num_ranks, num_experts);
178	    EP_HOST_ASSERT(num_notify_warps % 4 == 0);
179	
180	    // Other warps
181	    int num_dispatch_warps = 0;
182	    int num_scaleout_warps = 0, num_forward_warps = 0;
183	    int num_threads = 0;
184	
185	    // Maximize shared memory utilization
186	    if (num_scaleout_ranks == 1) {
187	        const auto token_layout = get_dispatch_token_layout(hidden, elem_size, num_sf_packs, num_topk);
188	        num_dispatch_warps = std::min<int>(
189	            (num_smem_bytes - num_notify_smem_bytes) / token_layout.get_num_bytes<true>(), 32 - num_notify_warps);
190	        num_threads = (num_notify_warps + num_dispatch_warps) * 32;
191	    } else {
192	        // Hybrid kernels
193	        num_scaleout_warps = num_channels_per_sm;
194	        num_forward_warps = num_channels_per_sm;
195	        num_threads = (num_notify_warps + num_scaleout_warps + num_forward_warps) * 32;
196	    }
197	
198	    // Generate, build and launch
199	    const DispatchRuntime::Args args = {
200	        .is_scaleup_nvlink = is_scaleup_nvlink,
201	        .do_cpu_sync = do_cpu_sync,
202	        .reuse_slot_indices = reuse_slot_indices,
203	        .num_notify_warps = num_notify_warps,
204	        .num_dispatch_warps = num_dispatch_warps,
205	        .num_scaleout_warps = num_scaleout_warps, .num_forward_warps = num_forward_warps,
206	        .num_scaleout_ranks = num_scaleout_ranks, .num_scaleup_ranks = num_scaleup_ranks,
207	        .num_hidden_bytes = hidden * elem_size, .num_sf_packs = num_sf_packs,
208	        .num_max_tokens_per_rank = num_max_tokens_per_rank,
209	        .num_experts = num_experts, .num_topk = num_topk, .expert_alignment = expert_alignment,
210	        .num_qps = num_qps, .num_timeout_cycles = num_timeout_cycles,
211	        .x = x, .sf = static_cast<sf_pack_t*>(sf), .topk_idx = topk_idx, .topk_weights = topk_weights,
212	        .copied_topk_idx = copied_topk_idx,
213	        .cumulative_local_expert_recv_stats = cumulative_local_expert_recv_stats,
214	        .psum_num_recv_tokens_per_scaleup_rank = psum_num_recv_tokens_per_scaleup_rank,
215	        .psum_num_recv_tokens_per_expert = psum_num_recv_tokens_per_expert,
216	        .num_unaligned_recv_tokens_per_expert = num_unaligned_recv_tokens_per_expert,
217	        .dst_buffer_slot_idx = dst_buffer_slot_idx,
218	        .token_metadata_at_forward = token_metadata_at_forward,
219	        .num_tokens = num_tokens,
220	        .sf_token_stride = sf_token_stride, .sf_hidden_stride = sf_hidden_stride,
221	        .nccl_dev_comm = nccl_dev_comm, .nccl_window = nccl_window,
222	        .buffer = buffer,
223	        .workspace = workspace, .mapped_host_workspace = mapped_host_workspace,
224	        .scaleout_rank_idx = scaleout_rank_idx, .scaleup_rank_idx = scaleup_rank_idx,
225	        // NOTES: make cluster dim 2 to overlap with clustered computation kernels
226	        .launch_args = jit::LaunchArgs(num_sms, num_threads, num_smem_bytes, 2 - (num_sms % 2), true)};
