43	    static int64_t get_num_bytes() {
44	        // Pure NVLink scaleup barrier signals
45	        int64_t num_bytes = 0;
46	        num_bytes += kNumBarrierSignalBytes;
47	
48	        // Notify reduction workspace
49	        num_bytes += (kNumMaxRanks + kNumMaxExperts) * sizeof(int64_t);
50	
51	        // Scaleup notify threads
52	        // Rank send/recv count
53	        num_bytes += kNumMaxRanks * sizeof(int64_t) * 2;
54	        // Expert send/recv count
55	        num_bytes += kNumMaxExperts * sizeof(int64_t) * 2;
56	
57	        // Scaleup atomic sender count
58	        num_bytes += kNumMaxRanks * sizeof(int);
59	
60	        // Scaleout notify threads
61	        // Rank send/recv count
62	        num_bytes += kNumMaxRanks * sizeof(int) * 2;
63	        // Expert send/recv count
64	        num_bytes += kNumMaxExperts * sizeof(int) * 2;
65	
66	        // Scaleout channel metadata (finish flag and tails)
67	        num_bytes += kNumMaxRanks * kNumMaxChannels * sizeof(int64_t);
68	
69	        // Channel aggregated into the scaleup domains
70	        // Also reused for channel scaleup tail
71	        num_bytes += kNumMaxRanks * kNumMaxChannels * sizeof(int);
72	
73	        // Rank send/recv count, for PP prev/next ranks
74	        num_bytes += 2 * 2 * sizeof(int64_t);
75	
76	        // AGRS signals
77	        num_bytes += (kNumMaxInflightAGRS + 1) * kNumMaxRanks * sizeof(int);
78	
79	        return num_bytes;
80	    }
